/**
 * Timesheet Aggregator (Date Range)
 * Groups timesheet rows by user + (Projekt + Tätigkeit + Datum + Start + Ende),
 * optional date range is read from the incoming Webhook body.
 * NOW INCLUDES TRAVEL TIME: Reise field is counted in total billable hours and tracked separately.
 */
const body = $('Webhook').first().json.body || {};
const startDateStr = body.startDate || null; // Optional dd.mm.yyyy
const endDateStr   = body.endDate   || null; // Optional dd.mm.yyyy

const parseDate = (dateStr) => {
  // Expecting dd.mm.yyyy
  const parts = String(dateStr || '').split('.');
  if (parts.length !== 3) return new Date('Invalid');
  const [d, m, y] = parts;
  return new Date(`${y}-${m}-${d}`);
};

const isInRange = (date, start, end) => {
  if (start && date < start) return false;
  if (end && date > end) return false;
  return true;
};

const addOrUpdateProject = (projects, projekt, taetigkeit, datum, start, ende, stunden, reise) => {
  const existing = projects.find(
    p =>
      p.projekt === projekt &&
      p.taetigkeit === taetigkeit &&
      p.datum === datum &&
      p.start === start &&
      p.ende === ende
  );
  if (existing) {
    existing.stunden += stunden;
    existing.reise += reise;
  } else {
    projects.push({ projekt, taetigkeit, datum, start, ende, stunden, reise });
  }
};

const startDate = startDateStr ? parseDate(startDateStr) : null;
const endDate   = endDateStr   ? parseDate(endDateStr)   : null;

const grouped = {};

for (const { json: row } of items) {
  const rowDate = parseDate(row['Datum']);
  if (String(rowDate) === 'Invalid Date') continue;
  if (!isInRange(rowDate, startDate, endDate)) continue;

  const name   = row['Name'];
  const hours  = Number(row['Stunden']) || 0;
  const travelHours = Number(row['Reise']) || 0; // NEW: Travel time from Reise field
  const proj   = row['Projekt'];
  const taet   = row['Tätigkeit']; // exact header spelling in the sheet
  const datum  = row['Datum'];
  const start  = row['Start'];
  const ende   = row['Ende'];

  if (!grouped[name]) {
    grouped[name] = {
      username: name,
      projects: [],
      totalHours: 0,
      totalTravelHours: 0 // NEW: Separate tracking for travel time
    };
  }
  addOrUpdateProject(grouped[name].projects, proj, taet, datum, start, ende, hours, travelHours);
  grouped[name].totalHours += hours + travelHours; // UPDATED: Include Reise in totalHours
  grouped[name].totalTravelHours += travelHours; // NEW: Track travel time separately
}

return Object.values(grouped).map(userData => ({ json: userData }));

/**
 * CSV Base64 Generator (escaped)
 * Builds a CSV per user with proper CSV escaping and encodes as Base64.
 */
const body        = $('Webhook').first().json.body || {};
const phoneMap    = body?.users || {}; // { phone: "Name" }
const instance    = body?.instance;
const startDate   = body?.startDate || null;
const endDate     = body?.endDate || null;

const timesheets  = items.map(i => i.json); // aggregated per user from previous node
const results     = [];

const csvCell = (val) => {
  if (val === null || val === undefined) return '';
  const s = String(val);
  if (/[",\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
};

for (const [phone, name] of Object.entries(phoneMap)) {
  const sheet = timesheets.find(ts => (ts.username || ts.name) === name);
  if (!sheet) {
    // produce an item marking this recipient as skipped (no rows)
    results.push({
      json: {
        instance, phone, name,
        skipped: true,
        reason: 'No rows for user',
        fileName: null,
        message: null,
        fileData: null
      }
    });
    continue;
  }

  const message = `Hallo ${name},\n\nanbei findest du deine aktuelle Arbeitszeitenübersicht.\nVielen Dank für deinen Einsatz und deine zuverlässige Arbeit – wir schätzen das sehr!\n\nFalls du Fragen zu den Angaben hast, melde dich bitte jederzeit bei uns.\n\nViele Grüße\nDein Energy44 Team\n\nCrew Love is True Love`;

  let lines = [];

  // Combine User + Zeitraum into one row, occupying all columns
  const headerInfo = `User: ${name} | Zeitraum: ${startDate || '-'} bis ${endDate || '-'}`;
  lines.push([headerInfo, '', '', '', '', '', ''].map(csvCell).join(','));

  lines.push('');
  // Header now includes Reise column
  lines.push(['Datum','Start','Ende','Projekt','Tätigkeit','Stunden','Reise'].map(csvCell).join(','));

  for (const proj of sheet.projects || []) {
    lines.push([
      proj.datum,
      proj.start,
      proj.ende,
      proj.projekt,
      proj.taetigkeit,
      proj.stunden,
      proj.reise || 0  // Include Reise column in project data
    ].map(csvCell).join(','));
  }

  lines.push('');
  // Separate totals: working hours, travel time
  const totalTravelHours = sheet.totalTravelHours || 0;
  const totalWorkingHours = sheet.totalHours - totalTravelHours;
  lines.push(['Gesamt','','','','', totalWorkingHours, totalTravelHours].map(csvCell).join(','));

  // NEW LINE: Combined billable hours
  lines.push(['Insgesamt verrechenbare Stunden','','','','','', sheet.totalHours].map(csvCell).join(','));

  const csvContent = lines.join('\n');
  const fileName   = `${name.replace(/\s+/g, '_')}_Timesheet.csv`;
  const fileData   = Buffer.from(csvContent, 'utf-8').toString('base64');

  results.push({
    json: {
      instance, phone, name,
      skipped: false,
      reason: null,
      fileName,
      message,
      fileData
    }
  });
}

return results;

/**
 * Summarize Results
 * Builds a single JSON summary for Webhook response.
 */
const body      = $('Webhook').first().json.body || {};
const phoneMap  = body.users || {};
const generated = $('CSV Base64 Generator').all().map(i => i.json);
const sent      = $('Evolution-send-media-file').all().map(i => i.json);

// Index generated by phone for quick lookup
const genByPhone = new Map(generated.map(g => [g.phone, g]));

const successes = [];
const failures  = [];
const skipped   = [];

// Iterate over each intended recipient (phoneMap)
for (const [phone, name] of Object.entries(phoneMap)) {
  const gen = genByPhone.get(phone);
  if (!gen || gen.skipped) {
    skipped.push({ phone, name, reason: gen?.reason || 'No rows for user' });
    continue;
  }
  // Find corresponding HTTP result
  const match = sent.find(s => String(s?.body?.to || s?.request?.number || s?.json?.number || '').includes(phone) || s?.request?.body?.number === phone || s?.request?.number === phone);
  const status = (match && (match.statusCode || match.status)) || null;
  const ok = status && status >= 200 && status < 300;

  if (ok) {
    successes.push({ phone, name, statusCode: status, fileName: gen.fileName });
  } else {
    failures.push({
      phone,
      name,
      statusCode: status || 'unknown',
      error: match?.body?.error || match?.body || match?.message || 'send failed',
      fileName: gen.fileName
    });
  }
}

return [{
  json: {
    instance: body.instance || null,
    counts: {
      total: Object.keys(phoneMap).length,
      attempted: successes.length + failures.length,
      ok: successes.length,
      failed: failures.length,
      skipped: skipped.length
    },
    successes,
    failures,
    skipped
  }
}];
